#!/usr/bin/env python3
"""Generate all Mahabharata character JSON files for the character database.

Usage:
    python3 data/characters/generate_mahabharata.py
"""

import json
import os

BASE_DIR = os.path.dirname(os.path.abspath(__file__))

def write_character(subpath, data):
    filepath = os.path.join(BASE_DIR, subpath)
    os.makedirs(os.path.dirname(filepath), exist_ok=True)
    with open(filepath, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=4, ensure_ascii=False)
    return filepath

def build_char(key, char_id, name, aliases, role, gender, ethnicity, family, divine_origin, tags, timelines):
    return {key: {"metadata": {"character_id": char_id, "name": name, "aliases": aliases, "epic": "Mahabharata", "primary_role": role, "gender": gender, "ethnicity_cultural_context": ethnicity, "family_relations": family, "divine_origin": divine_origin, "tags": tags}, "timelines": timelines}}

def tl(stage, age, context, skin, height, build, face, hair, marks, clothing, jewelry, weapons, tone, pitch, speech, emotion, vis_prompt, aud_prompt):
    return {"timeline_stage": stage, "age_approximation": age, "context_description": context, "physical_appearance": {"skin_tone": skin, "height": height, "build": build, "facial_features": face, "hair": hair, "distinguishing_marks": marks}, "wardrobe_and_adornments": {"clothing": clothing, "jewelry": jewelry, "weapons_carried": weapons}, "audio_and_voice_characteristics": {"tone": tone, "pitch": pitch, "speech_style": speech, "emotional_baseline": emotion}, "cinematic_generation_prompts": {"visual_prompt": vis_prompt, "audio_prompt": aud_prompt}}

def mc(char_id, key, name, aliases, role, gender, ethnicity, family, divine, tags, subpath, stage, age, ctx, skin, ht, bld, face, hair, marks, cloth, jewel, weap, tone, pitch, speech, emo, vis, aud):
    return (subpath, build_char(key, char_id, name, aliases, role, gender, ethnicity, family, divine, tags, [tl(stage, age, ctx, skin, ht, bld, face, hair, marks, cloth, jewel, weap, tone, pitch, speech, emo, vis, aud)]))

def mc2(char_id, key, name, aliases, role, gender, ethnicity, family, divine, tags, subpath, timelines_data):
    tls = [tl(*t) for t in timelines_data]
    return (subpath, build_char(key, char_id, name, aliases, role, gender, ethnicity, family, divine, tags, tls))

