ALL_CHARS.extend(additional_chars)


def generate_all():
    count = 0
    for subpath, data in ALL_CHARS:
        filepath = write_character(subpath, data)
        key = list(data.keys())[0]
        name = data[key]["metadata"]["name"]
        char_id = data[key]["metadata"]["character_id"]
        print(f"  ✓ {char_id} — {name} → {os.path.basename(filepath)}")
        count += 1
    return count


if __name__ == "__main__":
    print("=" * 60)
    print("Generating Mythological Character Database — Mahabharata")
    print("=" * 60)
    total = generate_all()
    print(f"\n{'='*60}")
    print(f"Generated {total} Mahabharata character files")
    print(f"{'='*60}")
